refsection.programlisting:
image = imread(fullpath(getIPCVpath() + "/images/opencv_smarties.png"));
image = imresize(image, [240 320]);
h = size(image, 1);
w = size(image, 2);
rect = [round(w * 0.08) round(h * 0.08) round(w * 0.84) round(h * 0.84)];
[mask, foreground] = imgrabcut(image, rect, 5);
subplot(1, 2, 1);
imshow(image);
subplot(1, 2, 2);
imshow(foreground);
